#!/bin/bashset -eecho "=== 瀹為獙2锛氭惌寤?OpenVPN 鏈嶅姟鍣?==="echo "[1/6] 瀹夎渚濊禆 ..."dnf install -y epel-releasednf install -y openvpn easy-rsa wgetecho "[2/6] 閰嶇疆 easy-rsa ..."EASYRSA_DIR="/opt/easy-rsa"if [ ! -d "$EASYRSA_DIR" ]; then    mkdir -p "$EASYRSA_DIR"ficd "$EASYRSA_DIR"cp -a /usr/share/easy-rsa/3/* ./ 2>/dev/null || cp -a /usr/share/easy-rsa/3.*/* ./ 2>/dev/null# init varscat > vars << 'EOF'if [ -z "$EASYRSA_CALLER" ]; then    echo "You appear to be sourcing an Easy-RSA 'vars' file." >&2    return 1fiset_var EASYRSA_DN "cn_only"set_var EASYRSA_REQ_COUNTRY "CN"set_var EASYRSA_REQ_PROVINCE "GuangDong"set_var EASYRSA_REQ_CITY "DongGuan"set_var EASYRSA_REQ_ORG "school"set_var EASYRSA_REQ_EMAIL "admin@school.edu"set_var EASYRSA_NS_SUPPORT "yes"EOFecho "[3/6] 鐢熸垚璇佷功 ..."./easyrsa init-pkiecho "" | ./easyrsa build-ca nopassecho "" | ./easyrsa gen-req server nopassecho "yes" | ./easyrsa sign-req server server./easyrsa gen-dhecho "" | ./easyrsa gen-req client nopassecho "yes" | ./easyrsa sign-req client clientecho "[4/6] 鍐欏叆鏈嶅姟绔厤缃?..."mkdir -p /etc/openvpn/servercat > /etc/openvpn/server/server.conf << 'EOF'port 1194proto udpdev tunca /opt/easy-rsa/pki/ca.crtcert /opt/easy-rsa/pki/issued/server.crtkey /opt/easy-rsa/pki/private/server.keydh /opt/easy-rsa/pki/dh.pemserver 10.8.0.0 255.255.255.0push "route 192.168.56.0 255.255.255.0"ifconfig-pool-persist ipp.txtkeepalive 10 120max-clients 100status openvpn-status.loglog /var/log/openvpn.logverb 3client-to-clientpersist-keypersist-tunduplicate-cncomp-lzoEOFecho "[5/6] 閰嶇疆闃茬伀澧?..."firewall-cmd --permanent --add-port=1194/udp 2>/dev/null || truefirewall-cmd --reload 2>/dev/null || trueecho "[6/6] 鍚姩鏈嶅姟 ..."systemctl enable openvpn-server@serversystemctl start openvpn-server@serverecho ""echo "=== 瀹為獙2 瀹夎瀹屾垚 ==="echo "瀹㈡埛绔瘉涔︿綅缃細"echo "  CA:   /opt/easy-rsa/pki/ca.crt"echo "  Cert: /opt/easy-rsa/pki/issued/client.crt"echo "  Key:  /opt/easy-rsa/pki/private/client.key"